import React, { useState, useCallback, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { GoogleMap, LoadScript, Marker, InfoWindow } from '@react-google-maps/api';

const PropertyMap = () => {
  const [searchParams] = useSearchParams();

  // Read URL params from PropertyDetail navigation
  const focusLat = searchParams.get('lat');
  const focusLng = searchParams.get('lng');
  const focusId  = searchParams.get('id');

  const [properties, setProperties] = useState([]);
  const [selectedProperty, setSelectedProperty] = useState(null);
  const [mapRef, setMapRef] = useState(null);

  // Center on focused property if params exist, otherwise default to HCM City
  const [center] = useState(
    focusLat && focusLng
      ? { lat: parseFloat(focusLat), lng: parseFloat(focusLng) }
      : { lat: 10.7769, lng: 106.7009 }
  );

  const mapContainerStyle = {
    width: '100%',
    height: '600px'
  };

  // Fetch properties for map
  const fetchProperties = useCallback(async (bounds = null) => {
    try {
      const url = `http://localhost:5001/api/properties/map${
        bounds ? `?bounds=${JSON.stringify(bounds)}` : ''
      }`;
      const response = await fetch(url);
      const data = await response.json();
      if (data.success) {
        setProperties(data.data);
      }
    } catch (error) {
      console.error('Error fetching properties:', error);
    }
  }, []);

  // After properties load, auto-select the focused property
  useEffect(() => {
    if (focusId && properties.length > 0) {
      const target = properties.find(p => p.id === parseInt(focusId));
      if (target) {
        setSelectedProperty(target);
      }
    }
  }, [properties, focusId]);

  // Handle map load
  const onLoad = useCallback((map) => {
    setMapRef(map);
    fetchProperties();
  }, [fetchProperties]);

  // Handle bounds change (drag/zoom)
  const onBoundsChanged = useCallback(() => {
    if (mapRef) {
      const bounds = mapRef.getBounds();
      if (bounds) {
        fetchProperties({
          north: bounds.getNorthEast().lat(),
          south: bounds.getSouthWest().lat(),
          east:  bounds.getNorthEast().lng(),
          west:  bounds.getSouthWest().lng()
        });
      }
    }
  }, [mapRef, fetchProperties]);

  const formatPrice = (price) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND'
    }).format(price);
  };

  return (
    <div className="map-page" style={{ padding: '1rem' }}>
      <h1 style={{ marginBottom: '1rem' }}>🗺️ Bản Đồ Bất Động Sản</h1>

      <LoadScript googleMapsApiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
        <GoogleMap
          mapContainerStyle={mapContainerStyle}
          center={center}
          zoom={focusLat && focusLng ? 15 : 12}
          onLoad={onLoad}
          onDragEnd={onBoundsChanged}
          onZoomChanged={onBoundsChanged}
        >
          {properties.map((property) => (
            <Marker
              key={property.id}
              position={property.position}
              title={property.title}
              // Highlight the focused property with a different color
              icon={
                focusId && property.id === parseInt(focusId)
                  ? {
                      url: 'http://maps.google.com/mapfiles/ms/icons/blue-dot.png'
                    }
                  : undefined
              }
              onClick={() => setSelectedProperty(property)}
            />
          ))}

          {selectedProperty && (
            <InfoWindow
              position={selectedProperty.position}
              onCloseClick={() => setSelectedProperty(null)}
            >
              <div style={{ maxWidth: '220px' }}>
                <h3 style={{ margin: '0 0 8px', fontSize: '14px' }}>
                  {selectedProperty.title}
                </h3>
                <p style={{ margin: '0 0 4px', fontWeight: 'bold', color: '#e53935' }}>
                  {formatPrice(selectedProperty.price)}
                </p>
                <p style={{ margin: '0 0 4px', fontSize: '12px', color: '#666' }}>
                  {selectedProperty.address}
                </p>
                {selectedProperty.distance && (
                  <p style={{ margin: '0 0 4px', fontSize: '12px', color: '#1976d2' }}>
                    📍 {selectedProperty.distance.toFixed(2)} km
                  </p>
                )}
                <a
                  href={`/properties/${selectedProperty.id}`}
                  style={{ color: '#1976d2', fontSize: '12px', textDecoration: 'none' }}
                >
                  Xem Chi Tiết →
                </a>
              </div>
            </InfoWindow>
          )}
        </GoogleMap>
      </LoadScript>
    </div>
  );
};

export default PropertyMap;
